object Solution { def apply_transactions(startingBalances: Map[String, Any], transactions: Seq[Map[String, Any]]): Seq[Any] = { val balances = scala.collection.mutable.Map[String, Int]() ++ startingBalances.map { case (k, v) => k -> asInt(v) }; val rejected = scala.collection.mutable.ArrayBuffer[Int](); for ((txn, index) <- transactions.zipWithIndex) { txn.get("type").map(_.toString) match { case Some("DEPOSIT") => val account = txn.getOrElse("account", "").toString; if (balances.contains(account)) balances(account) += asInt(txn.getOrElse("amount", 0)) else rejected += index; case Some("WITHDRAW") => val account = txn.getOrElse("account", "").toString; val amount = asInt(txn.getOrElse("amount", 0)); if (balances.contains(account) && balances(account) >= amount) balances(account) -= amount else rejected += index; case Some("TRANSFER") => val src = txn.getOrElse("from", "").toString; val dst = txn.getOrElse("to", "").toString; val amount = asInt(txn.getOrElse("amount", 0)); if (balances.contains(src) && balances.contains(dst) && balances(src) >= amount) { balances(src) -= amount; balances(dst) += amount } else rejected += index; case _ => rejected += index } }; Seq(balances.toMap, rejected.toSeq) }; private def asInt(value: Any): Int = value match { case n: Int => n; case n: Long => n.toInt; case n: Double => n.toInt; case _ => 0 } }
